arguments.old_str:
using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    void ApplyMigrations(AppDbContext db)
    {
        var strategy = db.Database.CreateExecutionStrategy();
        strategy.Execute(() =>
        {
            using var transaction = db.Database.BeginTransaction();
            db.Database.Migrate();
            transaction.Commit();
        });
    }
}

arguments.new_str:
using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    // EF Core 9 manages its own transactions during Migrate(); wrapping in a
    // user transaction now throws. The execution strategy is also unnecessary
    // here because Migrate() handles retries internally.
    void ApplyMigrations(AppDbContext db)
    {
        db.Database.Migrate();
    }
}

